from __future__ import annotations

from dataclasses import dataclass

from voxlocal._errors import EngineNotSupportedError, LanguageNotSupportedError


@dataclass(frozen=True)
class EngineConfig:
    """Resolved engine and model selection for one capability.

    Attributes:
        engine: Engine name (e.g. 'whisper', 'moonshine', 'supertonic').
        model_id: Model identifier for cache management.
        size_mb: Approximate model size in megabytes.
    """

    engine: str
    model_id: str
    size_mb: int

    def __repr__(self) -> str:
        return (
            f"EngineConfig(engine={self.engine!r}, "
            f"model_id={self.model_id!r}, size_mb={self.size_mb})"
        )

    def __getitem__(self, key: str) -> str | int:
        """Preserve the original mapping-style private API."""
        return getattr(self, key)


MODEL_REGISTRY: dict[str, dict[str, EngineConfig]] = {
    "stt": {
        "es": EngineConfig("moonshine", "moonshine_es", 60),
        "en": EngineConfig("sensevoice", "sensevoice_onnx", 230),
        "ja": EngineConfig("sensevoice", "sensevoice_onnx", 230),
        "ko": EngineConfig("sensevoice", "sensevoice_onnx", 230),
        "fr": EngineConfig("whisper", "whisper_base", 139),
        "de": EngineConfig("whisper", "whisper_base", 139),
        "pt": EngineConfig("whisper", "whisper_base", 139),
        "auto": EngineConfig("whisper", "whisper_base", 139),
    },
    "tts": {
        "es": EngineConfig("supertonic", "supertonic_3", 99),
        "en": EngineConfig("supertonic", "supertonic_3", 99),
        "ja": EngineConfig("supertonic", "supertonic_3", 99),
        "ko": EngineConfig("supertonic", "supertonic_3", 99),
        "fr": EngineConfig("supertonic", "supertonic_3", 99),
        "de": EngineConfig("supertonic", "supertonic_3", 99),
        "pt": EngineConfig("supertonic", "supertonic_3", 99),
    },
}

ENGINE_MODELS: dict[str, dict[str, dict[str, EngineConfig]]] = {
    "stt": {
        "whisper": {
            language: EngineConfig("whisper", "whisper_base", 139)
            for language in MODEL_REGISTRY["stt"]
        },
        "moonshine": {
            "es": EngineConfig("moonshine", "moonshine_es", 60),
        },
        "sensevoice": {
            language: EngineConfig("sensevoice", "sensevoice_onnx", 230)
            for language in ("en", "ja", "ko")
        },
    },
    "tts": {
        "supertonic": {
            language: EngineConfig("supertonic", "supertonic_3", 99)
            for language in MODEL_REGISTRY["tts"]
        }
    },
}

SUPPORTED_STT_LANGUAGES = tuple(sorted(MODEL_REGISTRY["stt"]))
SUPPORTED_TTS_LANGUAGES = tuple(sorted(MODEL_REGISTRY["tts"]))
SUPPORTED_LANGUAGES = sorted(
    set(MODEL_REGISTRY["stt"].keys()) | set(MODEL_REGISTRY["tts"].keys())
)


def _get_config(capability: str, language: str, engine: str | None) -> EngineConfig:
    if engine is None:
        try:
            return MODEL_REGISTRY[capability][language]
        except KeyError as error:
            raise LanguageNotSupportedError(language, capability) from error

    try:
        language_models = ENGINE_MODELS[capability][engine]
    except KeyError as error:
        raise EngineNotSupportedError(capability, engine, language) from error
    try:
        return language_models[language]
    except KeyError as error:
        raise EngineNotSupportedError(capability, engine, language) from error


def get_stt_config(language: str, engine: str | None = None) -> EngineConfig:
    """Resolve STT configuration, including explicit engine overrides."""
    return _get_config("stt", language, engine)


def get_tts_config(language: str, engine: str | None = None) -> EngineConfig:
    """Resolve TTS configuration, including explicit engine overrides."""
    return _get_config("tts", language, engine)

from __future__ import annotations

import logging
import time
from collections.abc import Iterator
from dataclasses import dataclass
from pathlib import Path

from platformdirs import user_cache_dir

from voxlocal._errors import (
    DependencyMissingError,
    ModelDownloadError,
    ModelNotDownloadedError,
)

logger = logging.getLogger("voxlocal.download")

DEFAULT_MAX_RETRIES = 3
DEFAULT_RETRY_BACKOFF_BASE = 1.5

SENSEVOICE_REPO = "lovemefan/SenseVoice-onnx"
SENSEVOICE_REVISION = "8a5ee5b014950890a07246bc590a4f77b3ef67a4"
SENSEVOICE_FILES = (
    "sense-voice-encoder-int8.onnx",
    "embedding.npy",
    "chn_jpn_yue_eng_ko_spectok.bpe.model",
    "am.mvn",
)
SUPERTONIC_FILES = (
    "onnx/tts.json",
    "onnx/unicode_indexer.json",
    "onnx/duration_predictor.onnx",
    "onnx/text_encoder.onnx",
    "onnx/vector_estimator.onnx",
    "onnx/vocoder.onnx",
    "voice_styles/M1.json",
)
MOONSHINE_ES_FILES = (
    "download.moonshine.ai/model/base-es/quantized/base-es/encoder_model.ort",
    "download.moonshine.ai/model/base-es/quantized/base-es/decoder_model_merged.ort",
    "download.moonshine.ai/model/base-es/quantized/base-es/tokenizer.bin",
)


@dataclass(frozen=True)
class DownloadProgress:
    """Observable model setup state."""

    model_id: str
    percent: int
    downloaded: str
    total: str
    description: str


class DownloadManager:
    """Own all model paths, availability checks, and explicit downloads.

    Args:
        cache_dir: Root directory for model storage. Uses platform user cache
            when not provided.
        max_retries: Maximum number of retry attempts for transient failures.
        retry_backoff_base: Base multiplier for exponential backoff.
    """

    def __init__(
        self,
        cache_dir: str | Path | None = None,
        *,
        max_retries: int = DEFAULT_MAX_RETRIES,
        retry_backoff_base: float = DEFAULT_RETRY_BACKOFF_BASE,
    ):
        root = cache_dir or user_cache_dir("voxlocal")
        self.cache_dir = Path(root).expanduser()
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        self.max_retries = max(0, max_retries)
        self.retry_backoff_base = max(1.0, retry_backoff_base)

    def is_downloaded(self, model_id: str) -> bool:
        """Return true only when required model files exist on disk."""
        if model_id == "supertonic_3":
            return self._all_exist(self.model_dir(model_id), SUPERTONIC_FILES)
        if model_id == "whisper_base":
            return (self.model_dir(model_id) / "base.pt").is_file()
        if model_id == "sensevoice_onnx":
            return self._all_exist(self.model_dir(model_id), SENSEVOICE_FILES)
        if model_id == "moonshine_es":
            return self._all_exist(self.model_dir(model_id), MOONSHINE_ES_FILES)
        raise ValueError(f"Unknown model: {model_id}")

    def require_downloaded(self, model_id: str) -> Path:
        """Return the model directory or raise the public setup error."""
        if not self.is_downloaded(model_id):
            raise ModelNotDownloadedError(model_id)
        return self.model_dir(model_id)

    def download(self, model_id: str) -> Iterator[DownloadProgress]:
        """Download one known model with explicit start and completion records.

        Retries transient failures with exponential backoff up to max_retries.

        Args:
            model_id: Identifier of the model to download.

        Yields:
            DownloadProgress records for each lifecycle event.

        Raises:
            ModelDownloadError: When download fails after all retries.
            DependencyMissingError: When required optional packages are missing.
            ValueError: When model_id is unknown.
        """
        if self.is_downloaded(model_id):
            yield self._progress(model_id, 100, "already cached")
            return

        yield self._progress(model_id, 0, "download started")
        last_error: Exception | None = None
        for attempt in range(1 + self.max_retries):
            try:
                if model_id == "supertonic_3":
                    self._download_supertonic()
                elif model_id == "whisper_base":
                    self._download_whisper()
                elif model_id == "sensevoice_onnx":
                    self._download_sensevoice()
                elif model_id == "moonshine_es":
                    self._download_moonshine()
                else:
                    raise ValueError(f"Unknown model: {model_id}")
                # Non-retryable errors
                break
            except (DependencyMissingError, ValueError):
                raise
            except Exception as error:
                last_error = error
                if attempt < self.max_retries:
                    backoff = self.retry_backoff_base**attempt
                    logger.warning(
                        "Download '%s' attempt %d/%d failed: %s. Retrying in %.1fs...",
                        model_id,
                        attempt + 1,
                        1 + self.max_retries,
                        error,
                        backoff,
                    )
                    time.sleep(backoff)
                else:
                    logger.error(
                        "Download '%s' failed after %d attempts: %s",
                        model_id,
                        1 + self.max_retries,
                        error,
                    )

        if last_error is not None and not self.is_downloaded(model_id):
            raise ModelDownloadError(
                f"Failed to download model '{model_id}' after "
                f"{1 + self.max_retries} attempts: {last_error}"
            ) from last_error

        if not self.is_downloaded(model_id):
            raise ModelDownloadError(
                f"Download for '{model_id}' completed without all required files"
            )
        yield self._progress(model_id, 100, "download complete")

    def model_dir(self, model_id: str) -> Path:
        """Return the engine-specific directory for a model."""
        directories = {
            "supertonic_3": self.cache_dir / "supertonic-3",
            "whisper_base": self.cache_dir / "whisper",
            "sensevoice_onnx": self.cache_dir / "sensevoice-onnx",
            "moonshine_es": self.cache_dir / "moonshine",
        }
        try:
            return directories[model_id]
        except KeyError as error:
            raise ValueError(f"Unknown model: {model_id}") from error

    def get_model_path(self, model_id: str) -> Path:
        """Backward-compatible alias for model_dir()."""
        return self.model_dir(model_id)

    @staticmethod
    def _all_exist(root: Path, relative_paths: tuple[str, ...]) -> bool:
        return all((root / relative_path).is_file() for relative_path in relative_paths)

    def cache_size_bytes(self) -> int:
        """Return total size of the model cache directory in bytes."""
        total = 0
        if self.cache_dir.is_dir():
            for path in self.cache_dir.rglob("*"):
                if path.is_file():
                    total += path.stat().st_size
        return total

    def cleanup_old_models(self, keep_last_n: int = 2) -> list[str]:
        """Remove model directories, keeping the most recently accessed.

        Args:
            keep_last_n: Number of most recently accessed models to retain.

        Returns:
            List of model IDs that were removed.
        """
        model_ids = list(self._model_directories().keys())
        if len(model_ids) <= keep_last_n:
            return []

        # Sort by access time (oldest first)
        model_dirs = [(mid, self.model_dir(mid)) for mid in model_ids]
        model_dirs.sort(key=lambda x: x[1].stat().st_atime if x[1].is_dir() else 0)

        removed: list[str] = []
        for mid, mdir in model_dirs[:-keep_last_n]:
            if mdir.is_dir():
                import shutil

                shutil.rmtree(mdir)
                removed.append(mid)
                logger.info("Cleaned up old model: %s", mid)
        return removed

    def _model_directories(self) -> dict[str, Path]:
        """Return mapping of model IDs to their directories."""
        directories = {
            "supertonic_3": self.cache_dir / "supertonic-3",
            "whisper_base": self.cache_dir / "whisper",
            "sensevoice_onnx": self.cache_dir / "sensevoice-onnx",
            "moonshine_es": self.cache_dir / "moonshine",
        }
        return directories

    @staticmethod
    def _progress(model_id: str, percent: int, description: str) -> DownloadProgress:
        return DownloadProgress(
            model_id=model_id,
            percent=percent,
            downloaded="complete" if percent == 100 else "pending",
            total="unknown",
            description=f"{model_id}: {description}",
        )

    def _download_supertonic(self) -> None:
        try:
            from supertonic.loader import download_model
        except ImportError as error:
            raise DependencyMissingError("supertonic", "tts") from error

        model_dir = self.model_dir("supertonic_3")
        model_dir.parent.mkdir(parents=True, exist_ok=True)
        download_model(model_dir, model_name="supertonic-3")

    def _download_whisper(self) -> None:
        try:
            import whisper
        except ImportError as error:
            raise DependencyMissingError("openai-whisper", "whisper") from error

        model = whisper.load_model(
            "base", download_root=str(self.model_dir("whisper_base"))
        )
        del model

    def _download_sensevoice(self) -> None:
        try:
            from huggingface_hub import snapshot_download
        except ImportError as error:
            raise DependencyMissingError("huggingface-hub", "sensevoice") from error

        snapshot_download(
            repo_id=SENSEVOICE_REPO,
            revision=SENSEVOICE_REVISION,
            local_dir=str(self.model_dir("sensevoice_onnx")),
            allow_patterns=list(SENSEVOICE_FILES),
        )

    def _download_moonshine(self) -> None:
        try:
            from moonshine_voice import get_model_for_language
        except ImportError as error:
            raise DependencyMissingError("moonshine-voice", "moonshine") from error

        get_model_for_language("es", cache_root=self.model_dir("moonshine_es"))

from __future__ import annotations

import base64
import io
from dataclasses import dataclass
from pathlib import Path
from typing import Any

import numpy as np
import soundfile as sf


def _mono_float32(audio: np.ndarray) -> np.ndarray:
    """Normalize generated audio to a contiguous mono float32 array."""
    normalized = np.asarray(audio, dtype=np.float32)
    if normalized.ndim == 2 and 1 in normalized.shape:
        normalized = normalized.reshape(-1)
    if normalized.ndim != 1:
        raise ValueError("Audio must be a mono one-dimensional array")
    return np.ascontiguousarray(normalized)


def _pcm_s16le(audio: np.ndarray) -> bytes:
    """Encode normalized floating-point audio as portable signed PCM16."""
    clipped = np.clip(audio, -1.0, 1.0)
    return (clipped * 32767.0).astype("<i2").tobytes()


@dataclass(frozen=True)
class AudioResult:
    """Result of TTS synthesis.

    Attributes:
        numpy: Mono float32 numpy array of audio samples.
        sample_rate: Audio sample rate in Hz.

    Raises:
        ValueError: If sample_rate is not positive or audio is not mono.
    """

    numpy: np.ndarray
    sample_rate: int

    def __post_init__(self) -> None:
        if self.sample_rate <= 0:
            raise ValueError("sample_rate must be positive")
        object.__setattr__(self, "numpy", _mono_float32(self.numpy))

    @property
    def duration_seconds(self) -> float:
        """Audio duration in seconds."""
        return len(self.numpy) / self.sample_rate

    @property
    def bytes(self) -> bytes:
        """Convert to WAV bytes."""
        buf = io.BytesIO()
        sf.write(buf, self.numpy, self.sample_rate, format="WAV")
        return buf.getvalue()

    @property
    def pcm_s16le(self) -> bytes:
        """Raw mono signed 16-bit little-endian PCM."""
        return _pcm_s16le(self.numpy)

    def save(self, path: str | Path) -> None:
        """Save as WAV file."""
        sf.write(path, self.numpy, self.sample_rate)


@dataclass(frozen=True)
class AudioChunk:
    """Portable streaming audio block independent of playback libraries.

    Attributes:
        sequence: Monotonically increasing chunk index.
        numpy: Mono float32 numpy array of audio samples.
        sample_rate: Audio sample rate in Hz.
        final: True if this is the last chunk in the stream.
        source_chunk: Index of the source chunk that produced this block.

    Raises:
        ValueError: If sequence is negative, sample_rate is not positive,
            or audio is not mono.
    """

    sequence: int
    numpy: np.ndarray
    sample_rate: int
    final: bool = False
    source_chunk: int | None = None

    def __post_init__(self) -> None:
        if self.sequence < 0:
            raise ValueError("sequence must be non-negative")
        if self.sample_rate <= 0:
            raise ValueError("sample_rate must be positive")
        object.__setattr__(self, "numpy", _mono_float32(self.numpy))

    @property
    def duration_seconds(self) -> float:
        """Audio duration in seconds."""
        return len(self.numpy) / self.sample_rate

    @property
    def pcm_s16le(self) -> bytes:
        """Raw mono signed 16-bit little-endian PCM."""
        return _pcm_s16le(self.numpy)

    def to_wire_dict(self) -> dict[str, Any]:
        """Serialize metadata and PCM for NDJSON or message transports."""
        return {
            "type": "audio_chunk",
            "sequence": self.sequence,
            "sample_rate": self.sample_rate,
            "channels": 1,
            "encoding": "pcm_s16le",
            "final": self.final,
            "source_chunk": self.source_chunk,
            "audio_base64": base64.b64encode(self.pcm_s16le).decode("ascii"),
        }

class VoxLocalError(Exception):
    """Base exception for VoxLocal.

    All VoxLocal exceptions inherit from this class, allowing consumers to
    catch any library error with a single except clause.
    """


class LanguageNotSupportedError(VoxLocalError):
    """Raised when the requested language is not available."""

    def __init__(self, language: str, capability: str | None = None):
        self.language = language
        self.capability = capability
        detail = f" for {capability}" if capability else ""
        super().__init__(f"Language not supported{detail}: {language}")


class EngineNotSupportedError(VoxLocalError):
    """Raised when an engine cannot serve the requested language."""

    def __init__(self, capability: str, engine: str, language: str):
        self.capability = capability
        self.engine = engine
        self.language = language
        super().__init__(
            f"{capability.upper()} engine '{engine}' does not support language "
            f"'{language}'"
        )


class ModelNotDownloadedError(VoxLocalError):
    """Raised when a required model has not been downloaded."""

    def __init__(self, model_id: str, message: str | None = None):
        self.model_id = model_id
        self.message = (
            message
            or "Model not downloaded. Run v.setup() or "
            f"v.download_model('{model_id}') first."
        )
        super().__init__(self.message)


class ModelDownloadError(VoxLocalError):
    """Raised when model download or setup fails."""


class DependencyMissingError(VoxLocalError):
    """Raised when an optional feature dependency is unavailable."""

    def __init__(self, dependency: str, extra: str):
        self.dependency = dependency
        self.extra = extra
        super().__init__(
            f"Missing optional dependency '{dependency}'. "
            f"Install it with: pip install 'voxlocal[{extra}]'"
        )


class TranscriptionError(VoxLocalError):
    """Error during speech-to-text transcription."""


class SynthesisError(VoxLocalError):
    """Error during text-to-speech synthesis."""

