        "tts": {
            "languages": list(SUPPORTED_TTS_LANGUAGES),
            "engines": {
                name: {"languages": langs, "model_id": ENGINE_MODELS["tts"][name][langs[0]].model_id}
                for name, langs in tts_engines.items()
            },
